#Powershell to export AD user information (One-Line design for Remote sessions & RMM use cases)
powershell -Command "Import-Module ActiveDirectory -ErrorAction Stop; try { Get-ADUser -Filter * -Properties MemberOf,LastLogonDate,PasswordLastSet,PasswordNeverExpires,adminCount,AccountLockoutTime,LockedOut,PasswordExpired,CannotChangePassword,Enabled,PasswordNotRequired,userAccountControl,CanonicalName,CN,DisplayName,DistinguishedName,Description,SamAccountName,HomeDirectory,UserPrincipalName,ScriptPath,Company,Fax,EmailAddress,Pager,GivenName,Surname,Name,Mail,createTimeStamp,logonCount,Department,Title,Office,OfficePhone,Manager,MobilePhone,StreetAddress,Street,City,PostalCode -ErrorAction Stop | Select-Object @{Name='MemberOf';Expression={$_.MemberOf -join '|'}},ObjectClass,LastLogonDate,PasswordLastSet,PasswordNeverExpires,adminCount,AccountLockoutTime,LockedOut,PasswordExpired,CannotChangePassword,Enabled,PasswordNotRequired,userAccountControl,CanonicalName,CN,DisplayName,DistinguishedName,Description,SamAccountName,HomeDirectory,UserPrincipalName,ScriptPath,Company,Fax,EmailAddress,Pager,GivenName,Surname,Name,Mail,createTimeStamp,logonCount,Department,Title,Office,OfficePhone,Manager,MobilePhone,StreetAddress,Street,City,PostalCode | Export-Csv -Path 'C:\temp\ad-users.csv' -NoTypeInformation -ErrorAction Stop; Write-Host 'Successfully exported results to C:\temp\ad-users.csv' } catch { Write-Error ('An error occurred'); exit 1 }"